for name, info in base.items():
    path = Path('finetune') / 'data' / f'{name}.jsonl'
    with path.open('w', encoding='utf-8') as f:
        for user_prompt, assistant_resp in info['qa']:
            item = {
                'messages': [
                    {'role': 'system', 'content': info['system']},
                    {'role': 'user', 'content': user_prompt},
                    {'role': 'assistant', 'content': assistant_resp},
                ]
            }
            f.write(json.dumps(item, ensure_ascii=False) + '\n')

print('Updated datasets:')
for name in base:
    path = Path('finetune') / 'data' / f'{name}.jsonl'
    print(name, len(path.read_text('utf-8').splitlines()))
